// Supabase Edge Function: mollie-webhook
// Mollie stuurt POST met payment id als status verandert
// Deploy: supabase functions deploy mollie-webhook --no-verify-jwt
//
// SECURITY:
// - Geen auth token vereist (Mollie stuurt zonder auth)
// - Verificatie gebeurt door de payment ID op te halen bij Mollie (niet vertrouwen op wat binnenkomt)
// - Idempotent: zelfde payment ID meerdere keren verwerken is veilig

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.49.4';
import { confirmOrder } from '../_shared/confirm-order.ts';

serve(async (req) => {
  try {
    // Mollie sends application/x-www-form-urlencoded with just 'id' param
    const formData = await req.formData();
    const paymentId = formData.get('id') as string;

    if (!paymentId || typeof paymentId !== 'string' || !paymentId.match(/^tr_[a-zA-Z0-9]+$/)) {
      return new Response('Invalid payment id', { status: 400 });
    }

    const MOLLIE_API_KEY = Deno.env.get('MOLLIE_API_KEY');
    if (!MOLLIE_API_KEY) return new Response('Not configured', { status: 500 });

    // SECURITY: Verify the payment by fetching from Mollie
    // Don't trust whatever came in the webhook body — always refetch from Mollie
    const mollieResp = await fetch(`https://api.mollie.com/v2/payments/${paymentId}`, {
      headers: { 'Authorization': `Bearer ${MOLLIE_API_KEY}` },
    });

    if (!mollieResp.ok) {
      console.error(`Mollie fetch failed for ${paymentId}:`, mollieResp.status);
      return new Response('Failed to fetch payment', { status: 500 });
    }

    const payment = await mollieResp.json();
    const meta = payment.metadata || {};

    // Create admin client with service role
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    if (payment.status === 'paid') {
      const email = String(meta.email || '').trim().toLowerCase();
      const naam = String(meta.naam || '').trim().slice(0, 200);
      const bedrijf = String(meta.bedrijf || '').trim().slice(0, 200);

      if (!email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) {
        console.error('Invalid email in metadata:', email);
        return new Response('Invalid email', { status: 400 });
      }

      // Idempotent upsert — markeer betaald, laat confirmed_at op null voor admin-bevestiging
      // BTW-velden uit metadata (gezet door create-payment) meenemen
      const vatRuleApplied = String(meta.vat_rule_applied || '').slice(0, 40) || null;
      const vatRateRaw = meta.vat_rate;
      const vatRate = (typeof vatRateRaw === 'number') ? vatRateRaw : (typeof vatRateRaw === 'string' ? parseFloat(vatRateRaw) : 0) || 0;
      const subtotalRaw = meta.subtotal;
      const subtotal = (typeof subtotalRaw === 'number') ? subtotalRaw : (typeof subtotalRaw === 'string' ? parseFloat(subtotalRaw) : null);
      const vatAmountRaw = meta.vat_amount;
      const vatAmount = (typeof vatAmountRaw === 'number') ? vatAmountRaw : (typeof vatAmountRaw === 'string' ? parseFloat(vatAmountRaw) : 0) || 0;

      const { data: upserted, error: upsertErr } = await supabase.from('orders').upsert({
        payment_id: payment.id,
        plan: String(meta.plan || '').slice(0, 50),
        amount: parseFloat(payment.amount.value),
        subtotal: subtotal,
        vat_amount: vatAmount,
        vat_rate: vatRate,
        vat_rule_applied: vatRuleApplied,
        vat_valid: (meta.vat_valid === true || meta.vat_valid === false) ? meta.vat_valid : null,
        country: String(meta.country || '').slice(0, 4) || null,
        customer_type: (meta.customer_type === 'b2b' || meta.customer_type === 'b2c') ? meta.customer_type : null,
        naam,
        bedrijf,
        email,
        btw_nummer: String(meta.btw_nummer || '').slice(0, 50),
        status: 'paid',
        paid_at: new Date().toISOString(),
      }, { onConflict: 'payment_id' }).select('id').maybeSingle();

      if (upsertErr || !upserted) {
        console.error('Order upsert mislukt:', upsertErr);
        return new Response('Order upsert failed', { status: 500 });
      }

      // Auto-confirm: invite user, koppel order, maak factuur. Idempotent — als al bevestigd no-op.
      const result = await confirmOrder(supabase, upserted.id);
      if (!result.ok) {
        // Niet hard falen — webhook moet 200 teruggeven anders blijft Mollie retryen.
        // Order staat al op paid, admin kan handmatig bevestigen via /admin als auto-confirm faalt.
        console.error(`Auto-confirm faalde voor order ${upserted.id}: ${result.error}`);
      }
    } else if (['failed', 'canceled', 'expired'].includes(payment.status)) {
      // Log the failed attempt
      await supabase.from('orders').upsert({
        payment_id: payment.id,
        plan: String(meta.plan || '').slice(0, 50),
        amount: parseFloat(payment.amount?.value || '0'),
        naam: String(meta.naam || '').slice(0, 200),
        bedrijf: String(meta.bedrijf || '').slice(0, 200),
        email: String(meta.email || '').slice(0, 320),
        btw_nummer: String(meta.btw_nummer || '').slice(0, 50),
        status: payment.status,
      }, { onConflict: 'payment_id' });
    }

    return new Response('OK', { status: 200 });
  } catch (err) {
    console.error('Webhook error:', err);
    return new Response('Error', { status: 500 });
  }
});

// Shared logic: bevestig een betaalde order — invite user, koppel order, maak factuur.
// Aangeroepen vanuit:
//   - order-confirm (handmatig door admin)
//   - mollie-webhook (auto na status=paid)
// Idempotent: mag meerdere keren met dezelfde orderId gedraaid worden.

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2.49.4';
import { sendPaymentConfirmation } from './send-mail.ts';

const PLAN_TO_PAKKET: Record<string, string> = {
  'gap': 'gap',
  'nis2': 'nis2',
  'beleid': 'beleid',
  'preaudit': 'admin',
};
const PAKKET_RANK: Record<string, number> = { 'gap': 1, 'nis2': 2, 'beleid': 3, 'admin': 5 };

export type ConfirmResult =
  | { ok: true; user_id: string; invoice_number: string | null; invited_new_user: boolean; already_confirmed: boolean }
  | { ok: false; error: string; status: number };

export async function confirmOrder(
  supabase: SupabaseClient,
  orderId: string,
  opts: { siteUrl?: string } = {},
): Promise<ConfirmResult> {
  const { data: order, error: orderErr } = await supabase
    .from('orders').select('*').eq('id', orderId).maybeSingle();
  if (orderErr || !order) return { ok: false, error: 'Order niet gevonden', status: 404 };

  if (order.status !== 'paid') {
    return { ok: false, error: `Order heeft status "${order.status}", alleen "paid" kan bevestigd worden`, status: 400 };
  }

  const email = String(order.email || '').trim().toLowerCase();
  const naam = String(order.naam || '').slice(0, 200);
  const bedrijf = String(order.bedrijf || '').slice(0, 200);
  const pakket = PLAN_TO_PAKKET[order.plan] || 'gap';

  if (!email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) {
    return { ok: false, error: 'Ongeldig e-mailadres in order', status: 400 };
  }

  // Idempotency: al bevestigd? Geef bestaande state terug zonder opnieuw uit te nodigen of factuur te maken.
  // Maar als de bevestigings-mail nog niet verstuurd is (oude orders, of eerdere mailfout), alsnog versturen.
  if (order.confirmed_at) {
    const { data: inv } = await supabase
      .from('invoices').select('invoice_number').eq('payment_id', order.payment_id).maybeSingle();
    const invoiceNumberExisting = inv?.invoice_number ?? null;

    if (!order.confirmation_email_sent_at) {
      const mailResult = await sendPaymentConfirmation(supabase, {
        orderId: order.id,
        email,
        naam,
        bedrijf,
        plan: order.plan,
        amount: parseFloat(order.amount),
        invoiceNumber: invoiceNumberExisting,
        invitedNewUser: false,
      });
      if (!mailResult.ok) {
        console.error(`Bevestigings-mail (backfill) mislukt voor order ${order.id}: ${mailResult.error}`);
      }
    }

    return {
      ok: true,
      user_id: order.user_id || '',
      invoice_number: invoiceNumberExisting,
      invited_new_user: false,
      already_confirmed: true,
    };
  }

  // 1. Find or invite user
  const { data: existingUsers } = await supabase.auth.admin.listUsers();
  const existing = existingUsers.users.find((u) => u.email === email);
  let userId: string;
  let invitedNew = false;

  if (existing) {
    userId = existing.id;
    const cur = existing.app_metadata?.pakket;
    const newPakket = (PAKKET_RANK[pakket] || 0) > (PAKKET_RANK[cur] || 0) ? pakket : cur;
    await supabase.auth.admin.updateUserById(userId, {
      app_metadata: { ...existing.app_metadata, pakket: newPakket },
      user_metadata: { ...existing.user_metadata, naam, bedrijf },
    });
  } else {
    const siteUrl = opts.siteUrl || Deno.env.get('SITE_URL') || 'https://annex27.nl';
    const { data: invited, error: inviteErr } = await supabase.auth.admin.inviteUserByEmail(email, {
      data: { naam, bedrijf },
      redirectTo: `${siteUrl}/portal`,
    });
    if (inviteErr || !invited.user) {
      return { ok: false, error: 'User-invite mislukt: ' + (inviteErr?.message || 'unknown'), status: 500 };
    }
    userId = invited.user.id;
    invitedNew = true;
    await supabase.auth.admin.updateUserById(userId, { app_metadata: { pakket } });
  }

  // 2. Update order — link user_id + confirmed_at
  await supabase.from('orders').update({
    user_id: userId,
    confirmed_at: new Date().toISOString(),
  }).eq('id', orderId);

  // 3. Create invoice if not exists
  let invoiceNumber: string | null = null;
  const { data: existingInv } = await supabase
    .from('invoices').select('invoice_number').eq('payment_id', order.payment_id).maybeSingle();

  if (existingInv) {
    invoiceNumber = existingInv.invoice_number;
  } else {
    const year = new Date().getFullYear();
    const prefix = `${year}-`;
    const { data: last } = await supabase
      .from('invoices').select('invoice_number')
      .like('invoice_number', `${prefix}%`)
      .order('invoice_number', { ascending: false }).limit(1);
    let seq = 1;
    if (last && last[0]) {
      const m = /^(\d{4})-(\d+)$/.exec(last[0].invoice_number);
      if (m) seq = parseInt(m[2], 10) + 1;
    }
    invoiceNumber = `${prefix}${String(seq).padStart(4, '0')}`;

    const totalIncl = parseFloat(order.amount);
    const vatRuleApplied: string | null = order.vat_rule_applied || null;
    const vatRate: number = typeof order.vat_rate === 'number' ? order.vat_rate
      : (typeof order.vat_rate === 'string' ? parseFloat(order.vat_rate) : 0) || 0;

    let subtotal: number;
    let btwAmount: number;
    if (order.subtotal != null && order.vat_amount != null) {
      subtotal = parseFloat(order.subtotal);
      btwAmount = parseFloat(order.vat_amount);
    } else if (vatRate > 0) {
      subtotal = Math.round((totalIncl / (1 + vatRate)) * 100) / 100;
      btwAmount = Math.round((totalIncl - subtotal) * 100) / 100;
    } else {
      subtotal = totalIncl;
      btwAmount = 0;
    }

    let btwRegime: string;
    if (vatRuleApplied === 'reverse_charge') btwRegime = 'reverse_charge';
    else if (vatRate > 0) btwRegime = 'standard';
    else btwRegime = 'none';

    await supabase.from('invoices').insert({
      invoice_number: invoiceNumber,
      order_id: order.id,
      user_id: userId,
      naam, bedrijf, email,
      btw_nummer: String(order.btw_nummer || '').slice(0, 50) || null,
      adres: null,
      product: order.plan,
      omschrijving: null,
      subtotal, btw_amount: btwAmount, total: totalIncl,
      status: 'paid',
      btw_regime: btwRegime,
      vat_rule_applied: vatRuleApplied,
      vat_rate: vatRate,
      country: order.country || null,
      customer_type: order.customer_type || null,
      payment_method: 'mollie',
      payment_id: order.payment_id,
    });
  }

  // 4. Stuur betalingsbevestigings-mail (idempotent, faalt soft).
  // Faalt deze, log het en ga door — order is correct bevestigd, mail kan handmatig opnieuw.
  const mailResult = await sendPaymentConfirmation(supabase, {
    orderId: order.id,
    email,
    naam,
    bedrijf,
    plan: order.plan,
    amount: parseFloat(order.amount),
    invoiceNumber,
    invitedNewUser: invitedNew,
  });
  if (!mailResult.ok) {
    console.error(`Bevestigings-mail mislukt voor order ${order.id}: ${mailResult.error}`);
  }

  return {
    ok: true,
    user_id: userId,
    invoice_number: invoiceNumber,
    invited_new_user: invitedNew,
    already_confirmed: false,
  };
}

// Shared mail-helper voor edge functions, gebruikt Resend HTTP API.
// Vereist secret RESEND_API_KEY in Supabase Edge Function secrets.
//
// Verzendadres: info@annex27.nl (vereist DNS-verificatie van annex27.nl in Resend dashboard).

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2.49.4';

const FROM_ADDRESS = 'Annex27 <info@annex27.nl>';
const REPLY_TO = 'info@annex27.nl';
const PORTAL_URL = 'https://annex27.nl/portal';

const PLAN_LABELS: Record<string, string> = {
  'gap': 'Gap-analyse',
  'nis2': 'NIS2 Readiness',
  'beleid': 'Beleidspakket',
  'preaudit': 'Pre-audit Review',
};

interface SendArgs {
  to: string;
  subject: string;
  html: string;
  text: string;
  replyTo?: string;
}

interface ResendResponse {
  id?: string;
  message?: string;
  name?: string;
}

async function sendViaResend(args: SendArgs): Promise<{ ok: true; id: string } | { ok: false; error: string }> {
  const apiKey = Deno.env.get('RESEND_API_KEY');
  if (!apiKey) return { ok: false, error: 'RESEND_API_KEY niet geconfigureerd' };

  const resp = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      from: FROM_ADDRESS,
      to: [args.to],
      subject: args.subject,
      html: args.html,
      text: args.text,
      reply_to: args.replyTo || REPLY_TO,
    }),
  });

  const body = (await resp.json().catch(() => ({}))) as ResendResponse;
  if (!resp.ok || !body.id) {
    return { ok: false, error: body.message || `Resend HTTP ${resp.status}` };
  }
  return { ok: true, id: body.id };
}

interface PaymentConfirmationArgs {
  orderId: string;
  email: string;
  naam: string;
  bedrijf: string;
  plan: string;
  amount: number;
  invoiceNumber: string | null;
  invitedNewUser: boolean;
}

function escapeHtml(s: string): string {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function buildPaymentEmail(args: PaymentConfirmationArgs): { subject: string; html: string; text: string } {
  const planLabel = PLAN_LABELS[args.plan] || args.plan;
  const amountFormatted = new Intl.NumberFormat('nl-NL', { style: 'currency', currency: 'EUR' }).format(args.amount);
  const safeNaam = escapeHtml(args.naam);
  const safeBedrijf = escapeHtml(args.bedrijf);
  const invoiceLine = args.invoiceNumber
    ? `<tr><td style="padding:8px 0;color:#64748b;">Factuurnummer</td><td style="padding:8px 0;color:#0f172a;font-weight:600;text-align:right;">${escapeHtml(args.invoiceNumber)}</td></tr>`
    : '';

  const newUserBlock = args.invitedNewUser
    ? `<p style="margin:16px 0 0;font-size:14px;line-height:1.6;color:#475569;">U ontvangt apart een mail met een persoonlijke link om uw wachtwoord in te stellen. Daarna kunt u via onderstaande knop inloggen op het portaal.</p>`
    : `<p style="margin:16px 0 0;font-size:14px;line-height:1.6;color:#475569;">U kunt direct inloggen op het portaal met uw bestaande wachtwoord.</p>`;

  const subject = `Betaling ontvangen — ${planLabel}${args.invoiceNumber ? ` (factuur ${args.invoiceNumber})` : ''}`;

  const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width,initial-scale=1" />
<title>${escapeHtml(subject)}</title>
</head>
<body style="margin:0;padding:0;background:#F8FAFC;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Inter,sans-serif;color:#0f172a;">
  <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="background:#F8FAFC;">
    <tr><td align="center" style="padding:32px 16px;">
      <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="600" style="max-width:600px;background:#ffffff;border-radius:14px;overflow:hidden;border:1px solid #E2E8F0;">
        <tr><td style="padding:32px 32px 0;">
          <div style="display:inline-block;padding:6px 12px;background:#CCFBF1;color:#0F766E;font-size:12px;font-weight:700;letter-spacing:0.06em;text-transform:uppercase;border-radius:999px;">Betaling ontvangen</div>
          <h1 style="margin:18px 0 8px;font-size:24px;line-height:1.25;color:#0f172a;letter-spacing:-0.02em;">Welkom bij Annex27, ${safeNaam}.</h1>
          <p style="margin:0;font-size:15px;line-height:1.65;color:#475569;">We hebben uw betaling voor <strong style="color:#0f172a;">${escapeHtml(planLabel)}</strong> ontvangen. Hieronder de details van uw bestelling.</p>
        </td></tr>
        <tr><td style="padding:28px 32px 0;">
          <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="border-top:1px solid #E2E8F0;border-bottom:1px solid #E2E8F0;font-size:14px;">
            <tr><td style="padding:8px 0;color:#64748b;">Pakket</td><td style="padding:8px 0;color:#0f172a;font-weight:600;text-align:right;">${escapeHtml(planLabel)}</td></tr>
            <tr><td style="padding:8px 0;color:#64748b;">Organisatie</td><td style="padding:8px 0;color:#0f172a;font-weight:600;text-align:right;">${safeBedrijf}</td></tr>
            <tr><td style="padding:8px 0;color:#64748b;">Bedrag</td><td style="padding:8px 0;color:#0f172a;font-weight:600;text-align:right;">${amountFormatted}</td></tr>
            ${invoiceLine}
          </table>
        </td></tr>
        <tr><td style="padding:24px 32px 0;">
          <a href="${PORTAL_URL}" style="display:inline-block;padding:14px 24px;background:#0D9488;color:#ffffff;text-decoration:none;border-radius:10px;font-weight:700;font-size:15px;">Open portaal &rarr;</a>
          ${newUserBlock}
        </td></tr>
        <tr><td style="padding:32px 32px 0;">
          <h2 style="margin:0 0 8px;font-size:16px;line-height:1.3;color:#0f172a;letter-spacing:-0.01em;">Wat er nu gebeurt</h2>
          <ol style="margin:0;padding:0 0 0 20px;font-size:14px;line-height:1.7;color:#475569;">
            <li>U start in het dashboard met uw gap-analyse op basis van de 93 Annex A-controls.</li>
            <li>U uploadt evidence en vult toelichting in. Voortgang wordt continu opgeslagen.</li>
            <li>Binnen 48 uur na afronding reviewt Lead Auditor uw werk persoonlijk en ontvangt u uw signed-off rapport.</li>
          </ol>
        </td></tr>
        <tr><td style="padding:24px 32px 32px;">
          <p style="margin:0;font-size:13px;line-height:1.65;color:#94a3b8;">Vragen? Beantwoord deze mail of stuur direct een bericht naar <a href="mailto:info@annex27.nl" style="color:#0D9488;text-decoration:none;">info@annex27.nl</a>.</p>
        </td></tr>
        <tr><td style="padding:18px 32px;background:#F8FAFC;border-top:1px solid #E2E8F0;">
          <p style="margin:0;font-size:12px;line-height:1.6;color:#94a3b8;">Annex27 &middot; KBO 1006.203.170 &middot; <a href="https://annex27.nl" style="color:#94a3b8;text-decoration:underline;">annex27.nl</a></p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body>
</html>`;

  const text = `Welkom bij Annex27, ${args.naam}.

We hebben uw betaling voor ${planLabel} ontvangen.

Bestelling
- Pakket: ${planLabel}
- Organisatie: ${args.bedrijf}
- Bedrag: ${amountFormatted}${args.invoiceNumber ? `\n- Factuurnummer: ${args.invoiceNumber}` : ''}

Open uw portaal: ${PORTAL_URL}

${args.invitedNewUser
    ? 'U ontvangt apart een mail met een persoonlijke link om uw wachtwoord in te stellen.'
    : 'U kunt direct inloggen met uw bestaande wachtwoord.'}

Wat er nu gebeurt
1. U start in het dashboard met uw gap-analyse op basis van de 93 Annex A-controls.
2. U uploadt evidence en vult toelichting in. Voortgang wordt continu opgeslagen.
3. Binnen 48 uur na afronding reviewt Lead Auditor uw werk en ontvangt u uw signed-off rapport.

Vragen? Beantwoord deze mail of stuur naar info@annex27.nl.

Annex27 — KBO 1006.203.170 — annex27.nl
`;

  return { subject, html, text };
}

export async function sendPaymentConfirmation(
  supabase: SupabaseClient,
  args: PaymentConfirmationArgs,
): Promise<{ ok: true; id: string; alreadySent: boolean } | { ok: false; error: string }> {
  // Idempotency: re-fetch om race-conditions te voorkomen
  const { data: order } = await supabase
    .from('orders')
    .select('confirmation_email_sent_at')
    .eq('id', args.orderId)
    .maybeSingle();

  if (order?.confirmation_email_sent_at) {
    return { ok: true, id: 'noop', alreadySent: true };
  }

  const { subject, html, text } = buildPaymentEmail(args);
  const result = await sendViaResend({ to: args.email, subject, html, text });

  if (!result.ok) return { ok: false, error: result.error };

  // Markeer als verstuurd zodat retries niet dubbel sturen
  await supabase
    .from('orders')
    .update({ confirmation_email_sent_at: new Date().toISOString() })
    .eq('id', args.orderId);

  return { ok: true, id: result.id, alreadySent: false };
}
